import{c as a,Q as l,j as r,m as t}from"./chunks/framework.DVkeSyfh.js";const m=JSON.parse('{"title":"Build crates","description":"","frontmatter":{},"headers":[],"relativePath":"ru/workflows/build-crates.md","filePath":"ru/workflows/build-crates.md","lastUpdated":null}'),i={name:"ru/workflows/build-crates.md"};function s(o,e,d,c,n,p){return l(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="build-crates" tabindex="-1">Build crates <a class="header-anchor" href="#build-crates" aria-label="Permalink to &quot;Build crates&quot;">​</a></h1><p>Аудитория: DJs и music collectors<br> Цель: создавать review lists без иллюзии финального алгоритмического taste<br> Тип: how-to</p><p>Crate - это рабочий список: warmup pool, peak-time pool, left-field folder или short list для прослушивания позже.</p><h2 id="recommended-loop" tabindex="-1">Recommended loop <a class="header-anchor" href="#recommended-loop" aria-label="Permalink to &quot;Recommended loop&quot;">​</a></h2><ol><li>Начните с narrow seed: track, prompt, classifier или filter.</li><li>Search через подходящий mode.</li><li>Добавьте candidates в current set или export list.</li><li>Удалите tracks, которые не прошли listening check.</li><li>Повторите с другим seed или signal.</li></ol><h2 id="keep-crates-small" tabindex="-1">Keep crates small <a class="header-anchor" href="#keep-crates-small" aria-label="Permalink to &quot;Keep crates small&quot;">​</a></h2><p>Самые полезные crates - reviewed crates. Большие unreviewed exports часто становятся еще одной библиотекой, которую нужно разбирать.</p><p>Используйте <code>Track limit</code>, result limits и focused prompts, чтобы output был достаточно маленьким для inspection.</p><h2 id="mix-signals-deliberately" tabindex="-1">Mix signals deliberately <a class="header-anchor" href="#mix-signals-deliberately" aria-label="Permalink to &quot;Mix signals deliberately&quot;">​</a></h2><p>Хороший crate workflow часто смешивает signals:</p><ul><li>MERT for near audio neighbors;</li><li>SONARA for feature balance;</li><li>CLAP for descriptive searches;</li><li>CLASS for trained concepts;</li><li>SET for ordered previews.</li></ul><p>Не используйте MAEST genre labels как crate builder, если workflow не про запись или inspection genre metadata.</p>',12)])])}const f=a(i,[["render",s]]);export{m as __pageData,f as default};
